// Validate + build a 'saas signup lead'. We DON'T create the auth_users row
// directly — Mary qualifies on a call first, then provisions. This avoids
// fake/spam signups creating real platform accounts. The lead row carries
// the requested product(s) so Mary knows what to activate.
const body = $input.item.json.body || {};
const email = String(body.email || '').trim().toLowerCase();
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!email || !emailRe.test(email)) {
  return { json: { _empty: true, status: 400, error: 'Valid email required' } };
}
const fullName = String(body.full_name || body.name || '').trim().slice(0, 200);
if (!fullName) return { json: { _empty: true, status: 400, error: 'Full name required' } };
if (body.consent !== true && body.consent !== 'true' && body.consent !== 'on') {
  return { json: { _empty: true, status: 400, error: 'CASL consent required' } };
}

// product = which Crystallux product they want (from the marketing page CTA).
// Allowed: sales_engine, sentinel, ava, luxi, maxi, ciro, mga, smart_quote.
const allowedProducts = ['sales_engine','sentinel','ava','luxi','maxi','ciro','mga','smart_quote','unspecified'];
const rawProduct = String(body.product || 'unspecified').toLowerCase().replace(/-/g, '_');
const product = allowedProducts.indexOf(rawProduct) !== -1 ? rawProduct : 'unspecified';
const tier = String(body.tier || '').toLowerCase().slice(0, 40);

// industry tells us which vertical the buyer operates in — drives the
// archetype the engine uses for outreach personalization later.
const industry = String(body.industry || '').trim().slice(0, 80);

const leadRow = {
  full_name:           fullName,
  email:               email,
  phone:               String(body.phone || '').trim().slice(0, 40),
  company:             String(body.company || body.company_name || '').trim().slice(0, 200) || ('SaaS signup ' + email + ' ' + Date.now()).slice(0, 200),
  job_title:           String(body.job_title || body.role || '').trim().slice(0, 120),
  industry:            industry || 'saas',
  city:                String(body.city || '').trim().slice(0, 120),
  source:              'saas_client_signup',
  lead_status:         'New Lead',
  product_type:        'saas',
  lead_type:           'saas_signup',
  do_not_contact:      false,
  unsubscribed:        false,
  total_emails_sent:   0,
  lead_score:          80,
  notes:               'SaaS client signup for product=' + product + ' tier=' + (tier || '(unspecified)') + ' on ' + new Date().toISOString().slice(0,10) + '. Industry: ' + (industry || 'unspecified') + '. Message: ' + (String(body.message || '').slice(0, 1000) || '(none)'),
  updated_at:          new Date().toISOString()
};

const notifySubject = '[Crystallux] New SaaS signup: ' + fullName + ' wants ' + product + (tier ? ' (' + tier + ')' : '');
const notifyBody = 'New SaaS client signup intent:\n\n' +
  'Name: ' + fullName + '\n' +
  'Email: ' + email + '\n' +
  'Company: ' + (leadRow.company) + '\n' +
  'Phone: ' + (leadRow.phone || '(none)') + '\n' +
  'Industry: ' + (industry || '(unspecified)') + '\n' +
  'Product: ' + product + '\n' +
  'Tier: ' + (tier || '(none)') + '\n' +
  'Message: ' + (String(body.message || '').slice(0, 1000) || '(none)') + '\n\n' +
  'Action: schedule onboarding call within 24h, then provision the auth_users row + product flags in Supabase.';

return { json: { leadRow, email, fullName, product, tier, notifySubject, notifyBody } };

// Build the Postmark notification to Mary + the welcome auto-reply to the
// signer. Postmark will queue these if it's not yet approved — that's fine,
// they'll dispatch automatically once approval lands.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const leadRows = allOf('Insert Lead');
const leadId = leadRows.length > 0 ? leadRows[0].id : null;
// Even if leadId is null (duplicate email — they're already in leads), we
// STILL send the welcome email + notify Mary. From the signer's POV the action
// succeeded; from Mary's POV she gets an inquiry to follow up on.

const v = $('Validate + Build').item.json;

// Welcome auto-reply HTML — sent to the signer
const welcomeHtml = '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.55;color:#333;max-width:640px">' +
  '<h1 style="font-size:22px;font-weight:700;color:#0f172a;margin:0 0 14px;line-height:1.3;letter-spacing:-0.01em">Welcome aboard, ' + v.fullName.split(" ")[0] + '.</h1>' +
  '<p style="color:#475569;font-size:15px;line-height:1.6;margin:0 0 24px">Thanks for signing up for <strong style="color:#0f172a">' + v.product.replace(/_/g, ' ') + (v.tier ? ' on the ' + v.tier + ' tier' : '') + '</strong>. Your trial dashboard is ready right now — set your password below and look around.</p>' +
  '<div style="margin:0 0 28px"><a href="https://crystallux.org/forgot-password.html" style="display:inline-block;background:#7C3AED;color:#fff;font-weight:700;font-size:15px;padding:14px 30px;border-radius:10px;text-decoration:none">Set your password &amp; log in &#8594;</a><p style="font-size:13px;color:#64748b;margin:10px 0 0">Use this email (' + v.email + ') on the set-password page, then sign in to your dashboard.</p></div>' +
  '<p style="font-size:12px;font-weight:700;color:#64748b;letter-spacing:0.08em;text-transform:uppercase;margin:24px 0 14px">What happens next</p>' +
  '<ol style="padding-left:20px;margin:0 0 24px">' +
    '<li style="font-size:14px;color:#334155;line-height:1.6;margin-bottom:10px"><strong style="color:#0f172a">Within 24 hours.</strong> An onboarding specialist emails you a calendar link to book a 20-minute discovery call.</li>' +
    '<li style="font-size:14px;color:#334155;line-height:1.6;margin-bottom:10px"><strong style="color:#0f172a">Discovery call (20 minutes).</strong> We confirm the right product and tier for your business, walk through your goals, and answer every question. No slides, no pressure.</li>' +
    '<li style="font-size:14px;color:#334155;line-height:1.6;margin-bottom:10px"><strong style="color:#0f172a">Go live.</strong> On the call we switch your dashboard from trial to live and your first campaigns start running. No blank screens.</li>' +
    '<li style="font-size:14px;color:#334155;line-height:1.6"><strong style="color:#0f172a">Week 1 onboarding.</strong> Personal support every step. You will not be left staring at a blank screen.</li>' +
  '</ol>' +
  '<p style="font-size:14px;color:#475569;line-height:1.6;margin:0 0 20px">Need to reach us before then? Just reply to this email — we read every one.</p>' +
  '<p style="font-size:14px;color:#0f172a;margin:28px 0 0;font-weight:600">— The Crystallux Team</p>' +
  '<hr style="border:none;border-top:1px solid #e5e7eb;margin:24px 0">' +
  '<p style="font-size:11px;color:#94a3b8">You are receiving this because you signed up at crystallux.org. To unsubscribe, reply with "unsubscribe" and we will remove you immediately. Crystallux Inc., Guelph, Ontario, Canada.</p>' +
  '</div>';

return { json: {
  ok: true,
  lead_id: leadId,
  product: v.product,
  tier: v.tier,
  fullName: v.fullName,
  email: v.email,
  notify_to_mary: {
    From:    'info@crystallux.org',
    To:      'info@crystallux.org',
    Subject: v.notifySubject,
    HtmlBody: '<pre style="font-family:monospace">' + (v.notifyBody || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</pre>' + (leadId ? '<p><a href="https://admin.crystallux.org/pages/leads.html?lead_id=' + leadId + '">Open in admin -></a></p>' : ''),
    TextBody: v.notifyBody,
    MessageStream: 'outbound',
    Tag: 'saas-client-signup',
    Metadata: { lead_id: leadId || '', product: v.product, tier: v.tier }
  },
  welcome_to_signer: {
    From:    'info@crystallux.org',
    To:      v.email,
    Subject: 'Your Crystallux trial is ready — set your password',
    HtmlBody: welcomeHtml,
    TextBody: 'Hi ' + v.fullName.split(" ")[0] + ',\n\nYour trial dashboard for ' + v.product.replace(/_/g, ' ') + (v.tier ? ' (' + v.tier + ' tier)' : '') + ' is ready right now.\n\n1) Set your password: https://crystallux.org/forgot-password.html (use this email, ' + v.email + ').\n2) Log in: https://crystallux.org/login.html and you land on your dashboard.\n\nWithin 24 hours an onboarding specialist will also reach out to book a 20-minute call and switch you from trial to live leads.\n\nNeed us before then? Reply to this email or write to info@crystallux.org.\n\nTalk soon,\nThe Crystallux Team\ninfo@crystallux.org',
    MessageStream: 'outbound',
    Tag: 'saas-client-welcome',
    Metadata: { lead_id: leadId || '', product: v.product }
  }
} };

// Friendly response back to the page so it can show 'thanks' message.
const v = $('Build Emails').item.json;
return { json: {
  ok: v.ok !== false,
  lead_id: v.lead_id,
  message: 'Signup received. Our team will reach out within 24 hours to schedule your onboarding call.',
  product: v.product,
  tier: v.tier
} };
